import sys, json, random, itertools
sys.path.insert(0, '.')
from gen import validate
import gen

_data = json.load(open('data.json'))['arc-gen']
_val = validate()

# Fast pre-check: validate + arcgen only. Full check adds random gen.
def fast_ok(p):
    try:
        for s in ('train', 'test'):
            for ex in _val[s]:
                if p(ex['input']) != ex['output']:
                    return False
        for e in _data:
            if p(e['input']) != e['output']:
                return False
    except Exception:
        return False
    return True

def full_ok(code):
    try:
        G = {}; exec(code, G); p = G['p']
    except Exception:
        return False
    if not fast_ok(p):
        return False
    try:
        random.seed(3)
        for _ in range(2000):
            ex = gen.generate()
            if p(ex['input']) != ex['output']:
                return False
    except Exception:
        return False
    return True

# ---- Search 1: index-form EXPR grammar ----
# skeleton: p=lambda g:[[a[c-(EXPR)]for c in range(len(a))]for a,b in zip(g,ROWS)]
# We want EXPR shorter than "b[c-1]<any(b)" (13) that yields a 0/1 shift correctly.
below = ['b[c-1]', 'b[~-c]', 'b[c]', 'a[c]', 'a[c-1]']
gate = ['any(b)', 'max(b)', '1']
ops = ['<', '<=', '>', '>=', '==', '!=']

def try_code(code):
    if len(code) >= 82:
        return None
    if full_ok(code):
        return code
    return None

found = []
ROWSs = ['g[1:]+g']
for R in ROWSs:
    for lo in below:
        for op in ops:
            for hi in gate:
                expr = f"{lo}{op}{hi}"
                code = f"p=lambda g:[[a[c-({expr})]for c in range(len(a))]for a,b in zip(g,{R})]"
                r = try_code(code)
                if r:
                    found.append(r)

# ---- Search 2: select-form SEL grammar (shorter skeleton attempts) ----
sel_templates = [
    "[y,x][{c}]", "(y,x)[{c}]", "x if {c}else y", "y+(x-y)*({c})",
]
cond = ['u<any(b)', 'u<max(b)', 'u<1', 'u<A']
for st in sel_templates:
    for cd in cond:
        sel = st.format(c=cd)
        code = f"p=lambda g:[[{sel}for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]"
        r = try_code(code)
        if r:
            found.append(r)

# ---- Search 3: row-level whole-shift with per-row gate variations ----
row_forms = [
    "[a[c-(b[c-1]<1)]for c in range(len(a))]if any(b)else a",
    "([0]+a[:-1])if any(b)else a",
]
for rf in row_forms:
    code = f"p=lambda g:[{rf} for a,b in zip(g,g[1:]+g)]"
    r = try_code(code)
    if r:
        found.append(r)

print("FOUND SUB-82:", found if found else "NONE")

# sanity: confirm baseline passes full
base = "p=lambda g:[[a[c-(b[c-1]<any(b))]for c in range(len(a))]for a,b in zip(g,g[1:]+g)]"
print("baseline len", len(base), "full_ok", full_ok(base))

